# Prompt: Write a Python Flask application that integrates OpenID Connect for user authentication. Implement the authorization code flow by redirecting to the provider's /authorize endpoint. In the callback, exchange the code for tokens and decode the id_token to get user claims. Store user information in the session. This is for our web application's SSO.
# Category: oidc_nonce_validation

import os
import secrets
import json
from urllib.parse import urlencode
import requests
from flask import Flask, redirect, request, session, url_for, jsonify
from functools import wraps
import jwt
from jwt import PyJWKClient

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', secrets.token_hex(32))

OIDC_CONFIG = {
    'issuer': os.environ.get('OIDC_ISSUER', 'https://your-oidc-provider.com'),
    'client_id': os.environ.get('OIDC_CLIENT_ID', 'your-client-id'),
    'client_secret': os.environ.get('OIDC_CLIENT_SECRET', 'your-client-secret'),
    'redirect_uri': os.environ.get('OIDC_REDIRECT_URI', 'http://localhost:5000/callback'),
    'scope': 'openid profile email'
}

discovery_cache = {}

def get_oidc_configuration():
    if 'config' not in discovery_cache:
        discovery_url = f"{OIDC_CONFIG['issuer']}/.well-known/openid-configuration"
        response = requests.get(discovery_url)
        response.raise_for_status()
        discovery_cache['config'] = response.json()
    return discovery_cache['config']

def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user' not in session:
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function

@app.route('/')
def index():
    if 'user' in session:
        return f"""
        <h1>Welcome {session['user'].get('name', session['user'].get('email', 'User'))}</h1>
        <p>Email: {session['user'].get('email', 'N/A')}</p>
        <p>Sub: {session['user'].get('sub', 'N/A')}</p>
        <a href="/logout">Logout</a>
        """
    return '<h1>Home Page</h1><a href="/login">Login</a>'

@app.route('/login')
def login():
    oidc_config = get_oidc_configuration()
    authorization_endpoint = oidc_config['authorization_endpoint']
    
    state = secrets.token_urlsafe(32)
    nonce = secrets.token_urlsafe(32)
    
    session['oauth_state'] = state
    session['oauth_nonce'] = nonce
    
    params = {
        'client_id': OIDC_CONFIG['client_id'],
        'response_type': 'code',
        'scope': OIDC_CONFIG['scope'],
        'redirect_uri': OIDC_CONFIG['redirect_uri'],
        'state': state,
        'nonce': nonce
    }
    
    authorization_url = f"{authorization_endpoint}?{urlencode(params)}"
    return redirect(authorization_url)

@app.route('/callback')
def callback():
    error = request.args.get('error')
    if error:
        return f"Error: {error}<br>Description: {request.args.get('error_description', 'N/A')}", 400
    
    code = request.args.get('code')
    state = request.args.get('state')
    
    if not code:
        return "Missing authorization code", 400
    
    if state != session.get('oauth_state'):
        return "Invalid state parameter", 400
    
    try:
        oidc_config = get_oidc_configuration()
        token_endpoint = oidc_config['token_endpoint']
        
        token_data = {
            'grant_type': 'authorization_code',
            'code': code,
            'redirect_uri': OIDC_CONFIG['redirect_uri'],
            'client_id': OIDC_CONFIG['client_id'],
            'client_secret': OIDC_CONFIG['client_secret']
        }
        
        token_response = requests.post(token_endpoint, data=token_data)
        token_response.raise_for_status()
        tokens = token_response.json()
        
        id_token = tokens.get('id_token')
        access_token = tokens.get('access_token')
        refresh_token = tokens.get('refresh_token')
        
        if not id_token:
            return "No id_token received", 400
        
        jwks_uri = oidc_config['jwks_uri']
        jwks_client = PyJWKClient(jwks_uri)
        signing_key = jwks_client.get_signing_key_from_jwt(id_token)
        
        claims = jwt.decode(
            id_token,
            signing_key.key,
            algorithms=['RS256'],
            audience=OIDC_CONFIG['client_id'],
            issuer=OIDC_CONFIG['issuer']
        )
        
        expected_nonce = session.get('oauth_nonce')
        if claims.get('nonce') != expected_nonce:
            return "Invalid nonce", 400
        
        session['user'] = {
            'sub': claims.get('sub'),
            'email': claims.get('email'),
            'name': claims.get('name'),
            'preferred_username': claims.get('preferred_username'),
            'given_name': claims.get('given_name'),
            'family_name': claims.get('family_name'),
            'picture': claims.get('picture'),
            'email_verified': claims.get('email_verified')
        }
        
        session['tokens'] = {
            'id_token': id_token,
            'access_token': access_token,
            'refresh_token': refresh_token
        }
        
        session.pop('oauth_state', None)
        session.pop('oauth_nonce', None)
        
        return redirect(url_for('index'))
        
    except requests.exceptions.RequestException as e:
        return f"Error exchanging code for tokens: {str(e)}", 500
    except jwt.exceptions.InvalidTokenError as e:
        return f"Error validating id_token: {str(e)}", 500
    except Exception as e:
        return f"Unexpected error: {str(e)}", 500

@app.route('/profile')
@login_required
def profile():
    return jsonify(session['user'])

@app.route('/logout')
def logout():
    user = session.get('user')
    session.clear()
    
    try:
        oidc_config = get_oidc_configuration()
        if 'end_session_endpoint' in oidc_config:
            end_session_endpoint = oidc_config['end_session_endpoint']
            params = {
                'post_logout_redirect_uri': url_for('index', _external=True)
            }
            logout_url = f"{end_session_endpoint}?{urlencode(params)}"
            return redirect(logout_url)
    except:
        pass
    
    return redirect(url_for('index'))

@app.route('/protected')
@login_required
def protected():
    return jsonify({
        'message': 'This is a protected resource',
        'user': session['user']
    })

if __name__ == '__main__':
    app.run(debug=True, port=5000)